// Facebook Groups to post to (replace with real group IDs)
const groups = [
  { id: 'GROUP_ID_1', name: 'Small Business Owners', niche: 'local_biz', tone: 'helpful' },
  { id: 'GROUP_ID_2', name: 'Retirement Planning', niche: 'finance', tone: 'trustworthy' },
  { id: 'GROUP_ID_3', name: 'Digital Marketing Tips', niche: 'marketing', tone: 'educational' },
  { id: 'GROUP_ID_4', name: 'Side Hustle Ideas', niche: 'monetization', tone: 'motivational' },
  { id: 'GROUP_ID_5', name: 'Entrepreneurs Over 50', niche: 'boomer_biz', tone: 'relatable' }
];

const today = new Date().toISOString().split('T')[0];
const dayOfWeek = new Date().getDay();

// Rotate groups: 2-3 per day to avoid spam detection
const todayGroups = groups.filter((_, i) => (i + dayOfWeek) % 3 !== 0).slice(0, 3);

return todayGroups.map(g => ({ json: { ...g, date: today, dayOfWeek } }));

