const groupData = $('Set Group Config').item.json;
const aiResponse = $input.item.json;

const postText = aiResponse.content?.[0]?.text || 'Could not generate content';

return [{
  json: {
    groupId: groupData.id,
    groupName: groupData.name,
    niche: groupData.niche,
    postText: postText.trim(),
    date: groupData.date,
    generatedAt: new Date().toISOString()
  }
}];

const postData = $('Extract Post Text').item.json;
const fbResult = $input.item.json;

const success = !!fbResult.id;
const postId = fbResult.id || 'failed';
const error = fbResult.error?.message || '';

return [{
  json: {
    groupId: postData.groupId,
    groupName: postData.groupName,
    niche: postData.niche,
    postId,
    success,
    error,
    postText: postData.postText.substring(0, 200) + '...',
    postedAt: new Date().toISOString()
  }
}];

